/* eslint-disable jsx-a11y/alt-text */
import React from 'react';
import ReactPlayer from 'react-player';
import './Voyage.css';
import profile from './profile.jpg';
import Footer from './Footer';
import tambour_profile from './tambour-profile/jpg';

export default function Voyage() {
  return (
    <div className='voyage-container'>
      <div className="voyage-banner" >
        <ReactPlayer
          url='voyage.mp4'
          className="video"
          width="100%"
          height="100%"
          object-fit="cover"
          muted={true}
          playing={true}
          loop={true}
          controls={false}
          allowfullscreen={true} />
      </div>
      <div className="content">
        <div className='profile-content'>
          <h2>  Se reconnecter </h2>

          <p> Le voyage au tambour </p><br>

          </br><p> Partir rencontrer son animal totem, les esprits, trouver des messages et des soins, les vibrations du tambour nous emporte dans un univers magique. Issu de traditions chamanes, le voyage au tambour est utilisé pour communiquer avec les esprits en entrant dans ce qui est appelé le "monde invisible". Les chamanes sont considéré.e.s comme étant des guériseur.euse. On retrouve encore ces tradiction dans les peuples autochtones.</p>

          <p> Depuis les recherches ont avancé expliquant ce qui se passe lorsqu'on effectue un voyage. Les vibrations émises par le tambour nous mènent à ce qu'on appelle un état modifoé de conscience nous plongeant ainsi dans une sorte de rêve. C'est une expérience qui reste unique pour chacun.e et les ressentis sont différents. On peut y trouver un état de relaxation, un travail sur le lâcher prise et cesser le brouhaha mentale, trouver des réponses à nos questions, mieux comprendre nos états émotionnels...vous venez y cherchez ce que vous souhaitez ! </p>

          <p> En ce qui concerne les tarifs, les prix en collectifs sont en tarif libre avec un prix indicatif de 18 euros. Les prix en individuel en tarif libre avec un prix indiatif de 35 euros. </p>

          <p>
          </p>
        </div>
        <div>
          <img className='image-profile-yoga' src={tambour_profile} alt='profile' />
        </div>
      </div>
      <Footer />
    </div>
  );
}
